import { html, customElement } from "@umbraco-cms/backoffice/external/lit";
import { UmbModalBaseElement } from "@umbraco-cms/backoffice/modal";
import type { FormDesign } from "@umbraco-forms/generated";
import type {
  UmbTreeElement,
  UmbTreeItemModelBase,
} from "@umbraco-cms/backoffice/tree";
import { FormsFormDetailRepository } from "../../../repository/index.js";
import { FORMS_FORM_TREE_ALIAS } from "../../../tree/manifests.js";
import type { FormsFormCopyOptionsModalData } from "./index.js";
import { UmbRequestReloadChildrenOfEntityEvent } from "@umbraco-cms/backoffice/entity-action";
import { FORMS_FORM_FOLDER_ENTITY_TYPE, FORMS_FORM_ROOT_ENTITY_TYPE } from "../../../entities.js";
import { UMB_ACTION_EVENT_CONTEXT } from "@umbraco-cms/backoffice/action";
import { UMB_NOTIFICATION_CONTEXT } from "@umbraco-cms/backoffice/notification";

@customElement("forms-form-copy-options-modal")
export class FormsFormCopyOptionsModalElement extends UmbModalBaseElement<FormsFormCopyOptionsModalData> {
  #formToCopy?: FormDesign | null;

  #formDetailRepository = new FormsFormDetailRepository(this);

  #notificationContext?: typeof UMB_NOTIFICATION_CONTEXT.TYPE;

  constructor() {
    super();

    this.consumeContext(UMB_NOTIFICATION_CONTEXT, (instance) => {
      this.#notificationContext = instance;
    });
  }


  async connectedCallback() {
    super.connectedCallback();

    if (!this.data?.unique) return;
    const { data } = await this.#formDetailRepository.requestByUnique(
      this.data.unique
    );
    this.#formToCopy = data;
    this.requestUpdate();
  }

  async #onSubmit(event: SubmitEvent) {
    event.preventDefault();
    if (!this.#formDetailRepository)
      throw new Error("Repository is not available");
    if (!this.data?.unique)
      throw new Error("Unique identifier is not available");

    const form = event.target as HTMLFormElement;
    if (!form) return;

    const isValid = form.checkValidity();
    if (!isValid) return;

    const formData = new FormData(form);
    const name = formData.get("NewName") as string;
    const copyWorkflows = formData.get("CopyWorkflows") === "on";
    const copyToFolderElement = this.shadowRoot?.getElementById(
      "CopyToFolder"
    ) as UmbTreeElement;
    const copyToFolderSelection = copyToFolderElement.getSelection()[0];
    const copyToFolder =
      copyToFolderSelection === undefined
        ? null // Nothing selected, so we keep the existing folder.
        : copyToFolderSelection === null
        ? "-1" // Root selected.
        : copyToFolderSelection; // Specific folder selected.

    const { error } = await this.#formDetailRepository.copyForm(
      this.data.unique,
      copyWorkflows,
      name,
      copyToFolder
    );

    if (!error) {
      const reloadEvent = new UmbRequestReloadChildrenOfEntityEvent({
        entityType: (copyToFolder === "-1" ? null : copyToFolder || null) ? FORMS_FORM_FOLDER_ENTITY_TYPE : FORMS_FORM_ROOT_ENTITY_TYPE,
        unique: copyToFolder === "-1" ? null : copyToFolder || null,
      });

      const eventContext = await this.getContext(UMB_ACTION_EVENT_CONTEXT);
      eventContext.dispatchEvent(reloadEvent);

      this.#notificationContext?.peek("positive", {
        data: { message: this.localize.term("formCopy_copySuccess") },
      });

      this._submitModal();
    } else {
      this.#notificationContext?.peek("danger", {
        data: { message: this.localize.term("formCopy_copyError") },
      });
      this._rejectModal();
    }
  }

  render() {
    return html`
      <umb-body-layout headline=${this.localize.term("formCopy_modalHeadline")}>
        <uui-box>
          <p>Copying form <b>${this.#formToCopy?.name}</b></p>
          <uui-form>
            <form id="CopyForm" @submit="${this.#onSubmit}">
              <uui-form-layout-item>
                <uui-label id="NewNameLabel" for="NewName" slot="label"
                  >${this.localize.term("formCopy_enterName")}</uui-label
                >
                <uui-input
                  type="text"
                  id="NewName"
                  name="NewName"
                  placeholder=${this.localize.term("formCopy_enterNewName")}
                ></uui-input>
              </uui-form-layout-item>
              <uui-form-layout-item>
                <uui-checkbox name="CopyWorkflows" label=${this.localize.term("formCopy_alsoCopyWorkflows")}
                  >${this.localize.term("formCopy_alsoCopyWorkflows")}</uui-checkbox
                >
                <div><small>${this.localize.term("formCopy_mandatoryWorkflowsCopied")}</small></div>
              </uui-form-layout-item>
              <uui-form-layout-item>
                <umb-tree
                  id="CopyToFolder"
                  alias="${FORMS_FORM_TREE_ALIAS}"
                  .props=${{
                    hideTreeRoot: false,
                    selectionConfiguration: {
                      multiple: false,
                    },
                    selectableFilter: (item: UmbTreeItemModelBase) =>
                      item.isFolder,
                  }}
                ></umb-tree>
              </uui-form-layout-item>
            </form>
          </uui-form>
        </uui-box>
        <uui-button
          slot="actions"
          id="cancel"
          label=${this.localize.term("general_cancel")}
          @click="${this._rejectModal}"
          >${this.localize.term("general_cancel")}</uui-button
        >
        <uui-button
          form="CopyForm"
          slot="actions"
          type="submit"
          label=${this.localize.term("general_copy")}
          look="primary"
          color="positive"
        ></uui-button>
      </umb-body-layout>
    `;
  }
}

export default FormsFormCopyOptionsModalElement;

declare global {
  interface HTMLElementTagNameMap {
    "forms-form-copy-options-modal": FormsFormCopyOptionsModalElement;
  }
}
